export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronExpression, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const range = (from: number, to: number, step = 1): number[] => {
  const result: number[] = [];
  for (let i = from; i <= to; i += step) result.push(i);
  return result;
};

const assertInRange = (value: number, min: number, max: number, context: string): void => {
  if (value < min || value > max)
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
};

const parseField = (token: string, config: FieldConfig, fieldName: string): number[] => {
  const { min, max } = config;

  // Comma-separated list — recurse on each part
  if (token.includes(",")) {
    const values = token
      .split(",")
      .flatMap(part => parseField(part.trim(), config, fieldName));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (token === "*") return range(min, max);

  // Step value: */N or start/N
  if (token.includes("/")) {
    const [left, stepStr] = token.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1)
      throw new SyntaxError(`Invalid step value "${stepStr}" in field "${fieldName}"`);

    if (left === "*") return range(min, max, step);

    // Range with step: e.g. 1-10/2
    if (left.includes("-")) {
      const [fromStr, toStr] = left.split("-");
      const from = parseInt(fromStr, 10);
      const to   = parseInt(toStr, 10);
      if (isNaN(from) || isNaN(to))
        throw new SyntaxError(`Invalid range "${left}" in field "${fieldName}"`);
      assertInRange(from, min, max, fieldName);
      assertInRange(to,   min, max, fieldName);
      if (from > to)
        throw new RangeError(`Range start ${from} > end ${to} in field "${fieldName}"`);
      return range(from, to, step);
    }

    // Numeric start with step: e.g. 5/15
    const start = parseInt(left, 10);
    if (isNaN(start))
      throw new SyntaxError(`Invalid token "${token}" in field "${fieldName}"`);
    assertInRange(start, min, max, fieldName);
    return range(start, max, step);
  }

  // Range: e.g. 1-5
  if (token.includes("-")) {
    const [fromStr, toStr] = token.split("-");
    const from = parseInt(fromStr, 10);
    const to   = parseInt(toStr, 10);
    if (isNaN(from) || isNaN(to))
      throw new SyntaxError(`Invalid range "${token}" in field "${fieldName}"`);
    assertInRange(from, min, max, fieldName);
    assertInRange(to,   min, max, fieldName);
    if (from > to)
      throw new RangeError(`Range start ${from} > end ${to} in field "${fieldName}"`);
    return range(from, to);
  }

  // Single number
  const value = parseInt(token, 10);
  if (isNaN(value))
    throw new SyntaxError(`Invalid token "${token}" in field "${fieldName}"`);
  assertInRange(value, min, max, fieldName);
  return [value];
};

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new SyntaxError(
      `Expected 5 fields in cron expression, got ${fields.length}: "${expression}"`
    );

  const [minuteToken, hourToken, domToken, monthToken, dowToken] = fields;
  const fieldNames = Object.keys(FIELD_CONFIGS) as (keyof CronExpression)[];
  const tokens     = [minuteToken, hourToken, domToken, monthToken, dowToken];

  const [minute, hour, dayOfMonth, month, dayOfWeek] = fieldNames.map((name, i) =>
    parseField(tokens[i], FIELD_CONFIGS[name], name)
  );

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

function expandRange(min: number, max: number): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i++) result.push(i);
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  const values = new Set<number>();

  for (const part of field.split(",")) {
    if (part === "*") {
      expandRange(min, max).forEach((v) => values.add(v));
    } else if (part.startsWith("*/")) {
      const step = parseInt(part.slice(2), 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value: ${part}`);
      }
      for (let i = min; i <= max; i += step) values.add(i);
    } else if (part.includes("/")) {
      const [rangePart, stepPart] = part.split("/");
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value: ${part}`);
      }
      let rangeMin = min;
      let rangeMax = max;
      if (rangePart !== "*") {
        if (rangePart.includes("-")) {
          const [lo, hi] = rangePart.split("-").map((n) => parseInt(n, 10));
          if (isNaN(lo) || isNaN(hi)) throw new Error(`Invalid range: ${part}`);
          rangeMin = lo;
          rangeMax = hi;
        } else {
          rangeMin = parseInt(rangePart, 10);
          if (isNaN(rangeMin)) throw new Error(`Invalid value: ${part}`);
          rangeMax = max;
        }
      }
      for (let i = rangeMin; i <= rangeMax; i += step) values.add(i);
    } else if (part.includes("-")) {
      const [lo, hi] = part.split("-").map((n) => parseInt(n, 10));
      if (isNaN(lo) || isNaN(hi)) throw new Error(`Invalid range: ${part}`);
      if (lo < min || hi > max || lo > hi) {
        throw new Error(`Range out of bounds: ${part} (valid: ${min}-${max})`);
      }
      expandRange(lo, hi).forEach((v) => values.add(v));
    } else {
      const num = parseInt(part, 10);
      if (isNaN(num)) throw new Error(`Invalid value: ${part}`);
      if (num < min || num > max) {
        throw new Error(`Value ${num} out of range (valid: ${min}-${max})`);
      }
      values.add(num);
    }
  }

  return [...values].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const keys = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const result = {} as CronResult;

  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    const [min, max] = FIELD_RANGES[key];
    let parsed = parseField(fields[i], min, max);

    // Normalize dayOfWeek: treat 7 as 0 (both are Sunday)
    if (key === "dayOfWeek") {
      const normalized = new Set(parsed.map((v) => (v === 7 ? 0 : v)));
      parsed = [...normalized].sort((a, b) => a - b);
    }

    result[key] = parsed;
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) {
      result[prefix] = {};
    }
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      !(value instanceof RegExp)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

