const parseField = (field: string, config: FieldConfig): number[] => {
  const { min, max } = config;

  const validateValue = (v: number, context: string): number => {
    if (!Number.isInteger(v) || v < min || v > max) {
      throw new RangeError(
        `Value ${v} out of range [${min}, ${max}] in "${context}"`
      );
    }
    return v;
  };

  // Comma-separated list — recurse on each part and flatten
  if (field.includes(",")) {
    const parts = field.split(",");
    const values = parts.flatMap((part) => parseField(part.trim(), config));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Step value: */step or start-end/step
  if (field.includes("/")) {
    const [rangePart, stepPart] = field.split("/");
    const step = parseInt(stepPart, 10);

    if (!Number.isInteger(step) || step <= 0) {
      throw new RangeError(`Invalid step value "${stepPart}" in "${field}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map((x) => parseInt(x, 10));
      start = validateValue(s, field);
      end = validateValue(e, field);
      if (start > end) {
        throw new RangeError(`Invalid range ${start}-${end} in "${field}"`);
      }
    } else {
      start = validateValue(parseInt(rangePart, 10), field);
      end = max;
    }

    const results: number[] = [];
    for (let i = start; i <= end; i += step) {
      results.push(i);
    }
    return results;
  }

  // Range: start-end
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = validateValue(parseInt(startStr, 10), field);
    const end = validateValue(parseInt(endStr, 10), field);

    if (start > end) {
      throw new RangeError(`Invalid range ${start}-${end} in "${field}"`);
    }

    return range(start, end);
  }

  // Wildcard
  if (field === "*") {
    return range(min, max);
  }

  // Single number
  const value = parseInt(field, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid cron field value: "${field}"`);
  }

  return [validateValue(value, field)];
};

