export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

function rangeArray(start: number, end: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}

function parseField(token: string, fieldName: keyof CronFields): number[] {
  const [min, max] = FIELD_RANGES[fieldName];

  // Comma-separated list — recurse on each part, flatten, deduplicate, sort
  if (token.includes(",")) {
    const values = token
      .split(",")
      .flatMap((part) => parseField(part.trim(), fieldName));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (token === "*") {
    return rangeArray(min, max);
  }

  // Step: */N or start-end/N
  if (token.includes("/")) {
    const [rangePart, stepPart] = token.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new RangeError(`Invalid step value in field "${fieldName}": "${token}"`);
    }

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map(Number);
        start = clamp(s, min, max);
        end   = clamp(e, min, max);
      } else {
        start = clamp(parseInt(rangePart, 10), min, max);
      }
    }

    if (start > end) {
      throw new RangeError(`Invalid range "${rangePart}" in field "${fieldName}"`);
    }

    return rangeArray(start, end, step);
  }

  // Range: start-end
  if (token.includes("-")) {
    const [startStr, endStr] = token.split("-");
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr,   10);

    if (isNaN(start) || isNaN(end)) {
      throw new TypeError(`Invalid range in field "${fieldName}": "${token}"`);
    }
    if (start < min || end > max || start > end) {
      throw new RangeError(
        `Range "${token}" out of bounds [${min}-${max}] for field "${fieldName}"`
      );
    }

    return rangeArray(start, end);
  }

  // Literal number
  const value = parseInt(token, 10);
  if (isNaN(value)) {
    throw new TypeError(`Invalid value in field "${fieldName}": "${token}"`);
  }
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of bounds [${min}-${max}] for field "${fieldName}"`
    );
  }

  return [value];
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new TypeError(
      `Expected 5 cron fields, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteToken, hourToken, domToken, monthToken, dowToken] = parts;

  return {
    minute:     parseField(minuteToken, "minute"),
    hour:       parseField(hourToken,   "hour"),
    dayOfMonth: parseField(domToken,    "dayOfMonth"),
    month:      parseField(monthToken,  "month"),
    dayOfWeek:  parseField(dowToken,    "dayOfWeek"),
  };
