type CronField = {
  min: number;
  max: number;
};

const FIELDS: Record<string, CronField> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

type FieldName = typeof FIELD_ORDER[number];

export type ParsedCron = Record<FieldName, number[]>;

function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}

function validateValue(value: number, field: CronField, fieldName: string): number {
  if (value < field.min || value > field.max) {
    throw new RangeError(
      `Value ${value} is out of range [${field.min}, ${field.max}] for field "${fieldName}"`
    );
  }
  return value;
}

function parseSegment(segment: string, field: CronField, fieldName: string): number[] {
  const { min, max } = field;

  // Wildcard: *
  if (segment === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Step value: */n or start/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value "${stepStr}" in field "${fieldName}"`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [startStr, endStr] = rangePart.split("-");
        rangeMin = validateValue(parseInt(startStr, 10), field, fieldName);
        rangeMax = validateValue(parseInt(endStr, 10), field, fieldName);
      } else {
        rangeMin = validateValue(parseInt(rangePart, 10), field, fieldName);
        rangeMax = max;
      }
    }

    if (rangeMin > rangeMax) {
      throw new RangeError(`Range start ${rangeMin} exceeds end ${rangeMax} in field "${fieldName}"`);
    }

    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: n-m
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = validateValue(parseInt(startStr, 10), field, fieldName);
    const end   = validateValue(parseInt(endStr, 10),   field, fieldName);

    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end} in field "${fieldName}"`);
    }

    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" in field "${fieldName}"`);
  }

  return [validateValue(value, field, fieldName)];
}

function parseField(expression: string, field: CronField, fieldName: string): number[] {
  const parts = expression.split(",");
  const values = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (!trimmed) {
      throw new SyntaxError(`Empty segment in field "${fieldName}"`);
    }
    for (const v of parseSegment(trimmed, field, fieldName)) {
      values.add(v);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new SyntaxError("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${parts.length}`
    );
  }

  const result = {} as ParsedCron;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const fieldDef  = FIELDS[fieldName];
    result[fieldName] = parseField(parts[i], fieldDef, fieldName);
  }

  return result;
}

interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronSchedule, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function parseField(expression: string, min: number, max: number): number[] {
  const results = new Set<number>();

  const parts = expression.split(",");

  for (const part of parts) {
    const trimmed = part.trim();

    if (trimmed === "*") {
      for (let i = min; i <= max; i++) results.add(i);
      continue;
    }

    if (trimmed.includes("/")) {
      const [rangePart, stepStr] = trimmed.split("/");
      const step = parseInt(stepStr, 10);

      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value: "${stepStr}"`);
      }

      let rangeMin = min;
      let rangeMax = max;

      if (rangePart !== "*") {
        if (rangePart.includes("-")) {
          const [startStr, endStr] = rangePart.split("-");
          rangeMin = parseInt(startStr, 10);
          rangeMax = parseInt(endStr, 10);
          if (isNaN(rangeMin) || isNaN(rangeMax)) {
            throw new Error(`Invalid range in step expression: "${rangePart}"`);
          }
        } else {
          rangeMin = parseInt(rangePart, 10);
          if (isNaN(rangeMin)) {
            throw new Error(`Invalid start value in step expression: "${rangePart}"`);
          }
          rangeMax = max;
        }
      }

      validateRange(rangeMin, rangeMax, min, max, trimmed);

      for (let i = rangeMin; i <= rangeMax; i += step) {
        results.add(i);
      }
      continue;
    }

    if (trimmed.includes("-")) {
      const [startStr, endStr] = trimmed.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);

      if (isNaN(start) || isNaN(end)) {
        throw new Error(`Invalid range: "${trimmed}"`);
      }

      validateRange(start, end, min, max, trimmed);

      for (let i = start; i <= end; i++) results.add(i);
      continue;
    }

    const value = parseInt(trimmed, 10);
    if (isNaN(value)) {
      throw new Error(`Invalid value: "${trimmed}"`);
    }

    if (value < min || value > max) {
      throw new Error(`Value ${value} out of range [${min}, ${max}]`);
    }

    results.add(value);
  }

  return Array.from(results).sort((a, b) => a - b);
}

function validateRange(
  start: number,
  end: number,
  min: number,
  max: number,
  original: string
): void {
  if (isNaN(start) || isNaN(end)) {
    throw new Error(`Invalid range: "${original}"`);
  }
  if (start > end) {
    throw new Error(`Range start ${start} is greater than end ${end} in "${original}"`);
  }
  if (start < min || end > max) {
    throw new Error(
      `Range "${original}" is out of bounds [${min}, ${max}]`
    );
  }
}

export default function parseCron(expression: string): CronSchedule {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${fields.length}. Format: "minute hour dayOfMonth month dayOfWeek"`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronSchedule)[];

  const result = {} as CronSchedule;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    try {
      result[name] = parseField(fields[i], min, max);
    } catch (err) {
      throw new Error(
        `Invalid ${name} field "${fields[i]}": ${(err as Error).message}`
      );
    }
  }

  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

function rangeArray(from: number, to: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = from; i <= to; i += step) result.push(i);
  return result;
}

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseField(expr: string, min: number, max: number): number[] {
  // Comma-separated list
  if (expr.includes(",")) {
    return expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), min, max))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  // Wildcard
  if (expr === "*") return rangeArray(min, max);

  // Step: */n or start/n
  if (expr.includes("/")) {
    const [left, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new SyntaxError(`Invalid step: "${stepStr}"`);
    const [from, to] = left === "*" ? [min, max] : (() => {
      const n = parseInt(left, 10);
      if (isNaN(n)) throw new SyntaxError(`Invalid step base: "${left}"`);
      return [clamp(n, min, max), max];
    })();
    return rangeArray(from, to, step);
  }

  // Range: a-b
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const from = clamp(parseInt(startStr, 10), min, max);
    const to   = clamp(parseInt(endStr,   10), min, max);
    if (from > to) throw new RangeError(`Invalid range: "${expr}"`);
    return rangeArray(from, to);
  }

  // Single number
  const n = parseInt(expr, 10);
  if (isNaN(n)) throw new SyntaxError(`Invalid cron token: "${expr}"`);
  return [clamp(n, min, max)];
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 cron fields, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;
  const fields = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const exprs  = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  return Object.fromEntries(
    fields.map((field, i) => {
      const [min, max] = FIELD_RANGES[field];
      return [field, parseField(exprs[i], min, max)];
    })
  ) as CronFields;
}

export default function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: Record<string, unknown> = {}
): Record<string, unknown> {
  if (obj === null || obj === undefined || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = obj;
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = (obj as Record<string, unknown>)[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as Record<string, unknown>, newKey, result);
    } else {
