}

function parseField(expr: string, min: number, max: number): number[] {
  // Comma-separated list
  if (expr.includes(",")) {
    const values = expr.split(",").flatMap((part) => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard with optional step: * or */N
  if (expr.startsWith("*")) {
    const stepPart = expr.slice(1);
    const step = stepPart.startsWith("/") ? parseInt(stepPart.slice(1), 10) : 1;
    if (isNaN(step) || step < 1) throw new RangeError(`Invalid step value in "${expr}"`);
    const result: number[] = [];
    for (let i = min; i <= max; i += step) result.push(i);
    return result;
  }

  // Range with optional step: N-M or N-M/S
  if (expr.includes("-")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = stepStr !== undefined ? parseInt(stepStr, 10) : 1;
    if (isNaN(step) || step < 1) throw new RangeError(`Invalid step in "${expr}"`);
    const [startStr, endStr] = rangePart.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);
    if (start > end) throw new RangeError(`Invalid range "${expr}": start > end`);
    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Plain number
  const value = parseInt(expr, 10);
  if (isNaN(value)) throw new SyntaxError(`Invalid cron field value: "${expr}"`);
  return [clamp(value, min, max)];
}

export default function parseCron(expression: string): CronFields {
