  }
  return value;
}

function parseField(expr: string, fieldName: keyof CronFields): number[] {
  const [min, max] = FIELD_RANGES[fieldName];

  // Comma-separated list — recurse on each part and flatten
  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), fieldName));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (expr === "*") {
    return range(min, max);
  }

  // Step: */n or start/n
  if (expr.includes("/")) {
    const [base, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in "${expr}"`);
    }
    const [from, to] = base === "*" ? [min, max] : base.includes("-")
      ? base.split("-").map((v) => parseInt(v, 10))
      : [parseInt(base, 10), max];
    if (isNaN(from) || isNaN(to)) {
      throw new SyntaxError(`Invalid step expression "${expr}"`);
    }
    clamp(from, min, max, fieldName);
    clamp(to, min, max, fieldName);
    const result: number[] = [];
    for (let v = from; v <= to; v += step) result.push(v);
    return result;
  }

  // Range: a-b
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range expression "${expr}"`);
    }
    clamp(start, min, max, fieldName);
    clamp(end, min, max, fieldName);
    return range(start, end);
  }

  // Single number
  const num = parseInt(expr, 10);
  if (isNaN(num)) {
    throw new SyntaxError(`Unrecognised cron token "${expr}" for field "${fieldName}"`);
  }
  clamp(num, min, max, fieldName);
  return [num];
}

