  // Comma-separated list
  if (expr.includes(",")) {
    return [...new Set(
      expr.split(",").flatMap(part => parseField(part.trim(), { min, max }))
    )].sort((a, b) => a - b);
  }

  // Wildcard
  if (expr === "*") {
    return range(min, max);
  }

  // Step value: */n or start-end/n
  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in "${expr}"`);
    }
    let start = min;
    let end = max;
    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map(Number);
        start = clamp(s, min, max);
        end = clamp(e, min, max);
        if (start > end) throw new RangeError(`Invalid range "${rangePart}"`);
      } else {
        start = clamp(parseInt(rangePart, 10), min, max);
      }
    }
    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);
    if (start > end) throw new RangeError(`Invalid range "${expr}"`);
    return range(start, end);
  }

