  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 cron fields, got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as CronResult;
  for (let i = 0; i < FIELDS.length; i++) {
    const [fieldName, fieldDef] = FIELDS[i];
    result[fieldName] = parseField(parts[i], fieldDef);
  }

  // Normalize dayOfWeek: treat 7 as 0 (both are Sunday)
  result.dayOfWeek = [
    ...new Set(result.dayOfWeek.map(d => (d === 7 ? 0 : d)))
  ].sort((a, b) => a - b);

  return result;
};

