export function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Expected 5 cron fields, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;
  const fieldNames = Object.keys(FIELD_CONFIGS) as (keyof CronFields)[];
  const exprs = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  const result = {} as CronFields;
  for (let i = 0; i < fieldNames.length; i++) {
    const key = fieldNames[i];
    result[key] = parseField(exprs[i], FIELD_CONFIGS[key]);
  }

  return result;
}

export default parseCron;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(expr: string, fieldName: keyof CronFields): number[] {
  const [min, max] = FIELD_RANGES[fieldName];

  if (expr === "*") {
    return range(min, max);
  }

  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), fieldName));
    const unique = [...new Set(values)].sort((a, b) => a - b);
    return unique;
  }

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in field "${fieldName}": "${expr}"`);
    }
    const result: number[] = [];
    for (let i = min; i <= max; i += step) result.push(i);
    return result;
  }

  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in field "${fieldName}": "${expr}"`);
    }
    const [rangeStart, rangeEnd] = rangePart.includes("-")
      ? rangePart.split("-").map((v) => parseInt(v, 10))
      : [parseInt(rangePart, 10), max];
    if (
      isNaN(rangeStart) ||
      isNaN(rangeEnd) ||
      rangeStart < min ||
      rangeEnd > max ||
      rangeStart > rangeEnd
    ) {
      throw new Error(`Invalid range in field "${fieldName}": "${expr}"`);
    }
    const result: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) result.push(i);
    return result;
  }

  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (
      isNaN(start) ||
      isNaN(end) ||
      start < min ||
      end > max ||
      start > end
    ) {
      throw new Error(`Invalid range in field "${fieldName}": "${expr}"`);
    }
    return range(start, end);
  }

  const value = parseInt(expr, 10);
  if (isNaN(value) || value < min || value > max) {
    throw new Error(
      `Invalid value in field "${fieldName}": "${expr}" (must be ${min}–${max})`
    );
  }
  return [value];
}

function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length}`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

export default parseCron;
export { parseCron, CronFields };

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

function expandRange(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function validateValue(value: number, min: number, max: number): number {
  if (value < min || value > max || !Number.isInteger(value)) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Comma-separated list
  if (segment.includes(",")) {
    return segment
      .split(",")
      .flatMap((part) => parseSegment(part.trim(), min, max))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(min, max);
  }

  // Step: */n or start-end/n or start/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new RangeError(`Invalid step: ${stepStr}`);

    let base: number[];
    if (rangePart === "*") {
      base = expandRange(min, max);
    } else if (rangePart.includes("-")) {
      const [lo, hi] = rangePart.split("-").map(Number);
      validateValue(lo, min, max);
      validateValue(hi, min, max);
      base = expandRange(lo, hi);
    } else {
      const start = parseInt(rangePart, 10);
      validateValue(start, min, max);
      base = expandRange(start, max);
    }

    return base.filter((_, i) => i % step === 0);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [loStr, hiStr] = segment.split("-");
    const lo = parseInt(loStr, 10);
    const hi = parseInt(hiStr, 10);
    validateValue(lo, min, max);
    validateValue(hi, min, max);
    return expandRange(lo, hi);
  }

  // Single value
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new TypeError(`Invalid cron field value: "${segment}"`);
  validateValue(value, min, max);
  return [value];
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new TypeError(
      `Expected 5 cron fields, got ${parts.length}: "${expression}"`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const result = {} as CronFields;

  for (let i = 0; i < fieldNames.length; i++) {
    const field = fieldNames[i];
    const [min, max] = FIELD_RANGES[field];
    result[field] = parseSegment(parts[i], min, max);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

