export default flattenObject;

type CronField = {
  min: number;
  max: number;
};

const FIELD_RANGES: Record<string, CronField> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 6 },
};

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

function clamp(value: number, min: number, max: number): number {
  return Math.min(Math.max(value, min), max);
}

function validateValue(value: number, field: CronField, fieldName: string): number {
  if (value < field.min || value > field.max) {
    throw new RangeError(
      `Value ${value} is out of range [${field.min}, ${field.max}] for field "${fieldName}"`
    );
  }
  return value;
}

function parseSegment(segment: string, field: CronField, fieldName: string): number[] {
  const { min, max } = field;

  // Wildcard
  if (segment === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => i + min);
  }

  // Step value: */step or start-end/step
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value "${stepPart}" in field "${fieldName}"`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [startStr, endStr] = rangePart.split("-");
        rangeMin = validateValue(parseInt(startStr, 10), field, fieldName);
        rangeMax = validateValue(parseInt(endStr, 10), field, fieldName);
      } else {
        rangeMin = validateValue(parseInt(rangePart, 10), field, fieldName);
      }
    }

    if (rangeMin > rangeMax) {
      throw new RangeError(`Range start ${rangeMin} > end ${rangeMax} in field "${fieldName}"`);
    }

    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = validateValue(parseInt(startStr, 10), field, fieldName);
    const end = validateValue(parseInt(endStr, 10), field, fieldName);

    if (start > end) {
      throw new RangeError(`Range start ${start} > end ${end} in field "${fieldName}"`);
    }

    return Array.from({ length: end - start + 1 }, (_, i) => i + start);
  }

  // Single number
  const num = parseInt(segment, 10);
  if (isNaN(num)) {
    throw new Error(`Invalid value "${segment}" in field "${fieldName}"`);
  }
  return [validateValue(num, field, fieldName)];
}

function parseField(expression: string, field: CronField, fieldName: string): number[] {
  const segments = expression.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const values = parseSegment(segment.trim(), field, fieldName);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (!expression || typeof expression !== "string") {
    throw new TypeError("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields in cron expression, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, FIELD_RANGES.minute, "minute"),
    hour: parseField(hourExpr, FIELD_RANGES.hour, "hour"),
    dayOfMonth: parseField(domExpr, FIELD_RANGES.dayOfMonth, "dayOfMonth"),
    month: parseField(monthExpr, FIELD_RANGES.month, "month"),
    dayOfWeek: parseField(dowExpr, FIELD_RANGES.dayOfWeek, "dayOfWeek"),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: Record<string, Primitive> = {}
): Record<string, Primitive> {
  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
