export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronExpression, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

function rangeArray(from: number, to: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = from; i <= to; i += step) result.push(i);
  return result;
}

function parseField(token: string, min: number, max: number): number[] {
  // Wildcard
  if (token === "*") return rangeArray(min, max);

  // Step: */n or start-end/n
  if (token.includes("/")) {
    const [rangePart, stepStr] = token.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step value: ${stepStr}`);

    let from = min;
    let to = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [a, b] = rangePart.split("-").map(Number);
        from = a;
        to = b;
      } else {
        from = parseInt(rangePart, 10);
      }
    }

    if (isNaN(from) || isNaN(to)) throw new Error(`Invalid range in: ${token}`);
    validate(from, min, max, token);
    validate(to, min, max, token);
    return rangeArray(from, to, step);
  }

  // Range: a-b
  if (token.includes("-")) {
    const [a, b] = token.split("-").map(Number);
    if (isNaN(a) || isNaN(b)) throw new Error(`Invalid range: ${token}`);
    validate(a, min, max, token);
    validate(b, min, max, token);
    if (a > b) throw new Error(`Range start exceeds end: ${token}`);
    return rangeArray(a, b);
  }

  // List: a,b,c
  if (token.includes(",")) {
    return token.split(",").flatMap(part => parseField(part.trim(), min, max));
  }

  // Single number
  const val = parseInt(token, 10);
  if (isNaN(val)) throw new Error(`Invalid cron token: ${token}`);
  validate(val, min, max, token);
  return [val];
}

function validate(val: number, min: number, max: number, token: string): void {
  if (val < min || val > max) {
    throw new RangeError(`Value ${val} out of range [${min}-${max}] in: ${token}`);
  }
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}: "${expression}"`);
  }

  const keys = Object.keys(FIELD_RANGES) as Array<keyof CronExpression>;

  return keys.reduce((acc, key, idx) => {
    const [min, max] = FIELD_RANGES[key];
    const values = parseField(fields[idx], min, max);
    const unique = [...new Set(values)].sort((a, b) => a - b);
    return { ...acc, [key]: unique };
  }, {} as CronExpression);
}

