  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type CronField = {
  values: number[];
};

type ParsedCron = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof ParsedCron, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }
    const rangeMin = rangePart === "*" ? min : parseInt(rangePart.split("-")[0], 10);
    const rangeMax = rangePart === "*" ? max : (rangePart.includes("-") ? parseInt(rangePart.split("-")[1], 10) : max);
    clamp(rangeMin, min, max);
    clamp(rangeMax, min, max);
    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard
  if (segment === "*") {
    const values: number[] = [];
    for (let i = min; i <= max; i++) {
      values.push(i);
    }
    return values;
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: ${segment}`);
    }
    clamp(start, min, max);
    clamp(end, min, max);
    if (start > end) {
      throw new RangeError(`Range start ${start} is greater than end ${end}`);
    }
    const values: number[] = [];
    for (let i = start; i <= end; i++) {
      values.push(i);
    }
    return values;
  }

  // Single number
  const num = parseInt(segment, 10);
  if (isNaN(num)) {
    throw new Error(`Invalid cron segment: ${segment}`);
  }
  clamp(num, min, max);
  return [num];
}

function parseField(field: string, min: number, max: number): number[] {
  const segments = field.split(",");
  const allValues = new Set<number>();

  for (const segment of segments) {
    const parsed = parseSegment(segment.trim(), min, max);
    for (const v of parsed) {
      // Normalize dayOfWeek: 7 is also Sunday (0)
      allValues.add(v);
    }
  }

  return Array.from(allValues).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = fields;
  const fieldKeys = Object.keys(FIELD_RANGES) as (keyof ParsedCron)[];

  const minute     = parseField(minuteStr, FIELD_RANGES.minute.min,     FIELD_RANGES.minute.max);
  const hour       = parseField(hourStr,   FIELD_RANGES.hour.min,       FIELD_RANGES.hour.max);
  const dayOfMonth = parseField(domStr,    FIELD_RANGES.dayOfMonth.min, FIELD_RANGES.dayOfMonth.max);
  const month      = parseField(monthStr,  FIELD_RANGES.month.min,      FIELD_RANGES.month.max);

  // dayOfWeek: normalize 7 → 0 (both mean Sunday)
  let dayOfWeek = parseField(dowStr, FIELD_RANGES.dayOfWeek.min, FIELD_RANGES.dayOfWeek.max);
  if (dayOfWeek.includes(7)) {
    const normalized = new Set(dayOfWeek.map(d => d === 7 ? 0 : d));
    dayOfWeek = Array.from(normalized).sort((a, b) => a - b);
  }

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

export default function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: Record<string, unknown> = {}
): Record<string, unknown> {
  for (const [key, value] of Object.entries(obj)) {
    const flatKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      !(value instanceof RegExp)
    ) {
      flattenObject(value as Record<string, unknown>, flatKey, result);
    } else {
      result[flatKey] = value;
    }
  }

  return result;
}

export default function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: Record<string, unknown> = {}
): Record<string, unknown> {
  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      !(value instanceof RegExp)
    ) {
      flattenObject(value as Record<string, unknown>, fullKey, result);
    } else {
      result[fullKey] = value;
    }
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (prefix) result[prefix] = JSON.stringify(obj) as unknown as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = Array.isArray(value)
        ? (JSON.stringify(value) as unknown as Primitive)
        : (value as Primitive);
    }
  }

  return result;
}

export default flattenObject;

type CronField = {
  min: number;
  max: number;
};

const FIELD_RANGES: Record<string, CronField> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 6 },
};

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}

function unique(arr: number[]): number[] {
  return [...new Set(arr)].sort((a, b) => a - b);
}

function parseField(expr: string, field: CronField): number[] {
  const { min, max } = field;

  // Comma-separated list
  if (expr.includes(",")) {
    return unique(
      expr
        .split(",")
        .flatMap((part) => parseField(part.trim(), field))
    );
  }

  // Step value: */step or start-end/step
  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in expression: "${expr}"`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [start, end] = rangePart.split("-").map(Number);
        if (isNaN(start) || isNaN(end)) {
          throw new Error(`Invalid range in step expression: "${expr}"`);
        }
        rangeMin = clamp(start, min, max);
        rangeMax = clamp(end, min, max);
        if (rangeMin > rangeMax) {
          throw new Error(`Range start exceeds end in expression: "${expr}"`);
        }
      } else {
        const start = parseInt(rangePart, 10);
        if (isNaN(start)) {
          throw new Error(`Invalid start value in step expression: "${expr}"`);
        }
        rangeMin = clamp(start, min, max);
      }
    }

    const result: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      result.push(i);
    }
    return result;
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range expression: "${expr}"`);
    }

    const rangeMin = clamp(start, min, max);
    const rangeMax = clamp(end, min, max);

    if (rangeMin > rangeMax) {
      throw new Error(`Range start exceeds end in expression: "${expr}"`);
    }

    const result: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i++) {
      result.push(i);
    }
    return result;
  }

  // Wildcard
  if (expr === "*") {
    const result: number[] = [];
    for (let i = min; i <= max; i++) {
      result.push(i);
    }
    return result;
  }

  // Single number
  const value = parseInt(expr, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron field expression: "${expr}"`);
  }

  if (value < min || value > max) {
    throw new Error(
      `Value ${value} out of valid range [${min}, ${max}] in expression: "${expr}"`
    );
  }

  return [value];
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] =
    parts;

  return {
    minute: parseField(minuteExpr, FIELD_RANGES.minute),
    hour: parseField(hourExpr, FIELD_RANGES.hour),
    dayOfMonth: parseField(dayOfMonthExpr, FIELD_RANGES.dayOfMonth),
    month: parseField(monthExpr, FIELD_RANGES.month),
    dayOfWeek: parseField(dayOfWeekExpr, FIELD_RANGES.dayOfWeek),
  };
}

type Primitive = string | number | boolean | null | undefined;

type FlattenedObject = Record<string, Primitive>;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<Primitive | NestedObject>;
};

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlattenedObject = {}
): FlattenedObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      if (prefix) result[prefix] = null;
      return result;
    }
    obj.forEach((item, index) => {
      const key = prefix ? `${prefix}.${index}` : String(index);
      if (item !== null && typeof item === "object" && !Array.isArray(item)) {
        flattenObject(item as NestedObject, key, result);
      } else if (Array.isArray(item)) {
        flattenObject(item as unknown as NestedObject, key, result);
      } else {
        result[key] = item as Primitive;
      }
    });
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (value !== null && typeof value === "object") {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0, 6],
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}]`);
  }
  return value;
}

function range(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseField(field: string, min: number, max: number): number[] {
  // Handle comma-separated list
  if (field.includes(",")) {
    return [...new Set(
      field.split(",").flatMap(part => parseField(part.trim(), min, max))
    )].sort((a, b) => a - b);
  }

  // Handle step values (e.g., "*/15" or "1-30/5")
  if (field.includes("/")) {
    const [rangeOrWild, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${stepStr}`);

    let start = min;
    let end = max;

    if (rangeOrWild !== "*") {
      const [s, e] = rangeOrWild.split("-").map(Number);
      start = clamp(s, min, max);
      end = clamp(e ?? s, min, max);
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Handle range (e.g., "1-5")
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);
    if (start > end) throw new RangeError(`Invalid range: ${field}`);
    return range(start, end);
  }

  // Handle wildcard
  if (field === "*") return range(min, max);

  // Handle single number
  const num = parseInt(field, 10);
  if (isNaN(num)) throw new Error(`Invalid cron field value: "${field}"`);
  return [clamp(num, min, max)];
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}: "${expression}"`);
  }

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = parts;
  const fieldOrder = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;
  const fieldStrs = [minuteStr, hourStr, domStr, monthStr, dowStr];

  const result = {} as CronFields;

  for (let i = 0; i < fieldOrder.length; i++) {
    const key = fieldOrder[i];
    const [min, max] = FIELD_RANGES[key];
    try {
      result[key] = parseField(fieldStrs[i], min, max);
    } catch (err) {
      throw new Error(`Invalid ${key} field "${fieldStrs[i]}": ${(err as Error).message}`);
    }
  }

  return result;
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronExpression, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const clamp = (value: number, min: number, max: number): number =>
  Math.min(Math.max(value, min), max);

function parseField(token: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Comma-separated list
  if (token.includes(",")) {
    return token
      .split(",")
      .flatMap(part => parseField(part.trim(), config))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  // Wildcard with optional step: * or */N
  if (token.startsWith("*")) {
    const stepMatch = token.match(/^\*\/(\d+)$/);
    if (stepMatch) {
      const step = parseInt(stepMatch[1], 10);
      if (step <= 0) throw new RangeError(`Step must be positive, got: ${step}`);
      const values: number[] = [];
      for (let v = min; v <= max; v += step) values.push(v);
      return values;
    }
    if (token === "*") return range(min, max);
    throw new SyntaxError(`Invalid wildcard expression: ${token}`);
  }

  // Range with optional step: N-M or N-M/S
  if (token.includes("-")) {
    const rangeStepMatch = token.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
    if (!rangeStepMatch) throw new SyntaxError(`Invalid range expression: ${token}`);

    const start = parseInt(rangeStepMatch[1], 10);
    const end   = parseInt(rangeStepMatch[2], 10);
    const step  = rangeStepMatch[3] ? parseInt(rangeStepMatch[3], 10) : 1;

    if (start < min || start > max) throw new RangeError(`Value ${start} out of range [${min}, ${max}]`);
    if (end   < min || end   > max) throw new RangeError(`Value ${end} out of range [${min}, ${max}]`);
    if (start > end)                throw new RangeError(`Range start ${start} > end ${end}`);
    if (step <= 0)                  throw new RangeError(`Step must be positive, got: ${step}`);

    const values: number[] = [];
    for (let v = start; v <= end; v += step) values.push(v);
    return values;
  }

  // Single number
  const num = parseInt(token, 10);
  if (isNaN(num))       throw new SyntaxError(`Invalid cron token: ${token}`);
  if (num < min || num > max) throw new RangeError(`Value ${num} out of range [${min}, ${max}]`);
  return [num];
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 cron fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteToken, hourToken, domToken, monthToken, dowToken] = fields;

  return {
    minute:     parseField(minuteToken, FIELD_CONFIGS.minute),
    hour:       parseField(hourToken,   FIELD_CONFIGS.hour),
    dayOfMonth: parseField(domToken,    FIELD_CONFIGS.dayOfMonth),
    month:      parseField(monthToken,  FIELD_CONFIGS.month),
    dayOfWeek:  parseField(dowToken,    FIELD_CONFIGS.dayOfWeek),
  };
}

export default function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: Record<string, unknown> = {}
): Record<string, unknown> {
  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      !(value instanceof RegExp)
    ) {
      flattenObject(value as Record<string, unknown>, fullKey, result);
    } else {
      result[fullKey] = value;
    }
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | unknown[];
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = obj as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | unknown[];
    }
  }

  return result;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function generateRange(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) {
    result.push(i);
  }
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  const allValues = generateRange(min, max);

  // Wildcard
  if (field === "*") {
    return allValues;
  }

  // Step value (e.g., "*/15" or "0-30/5")
  if (field.includes("/")) {
    const [rangePart, stepPart] = field.split("/");
    const step = parseInt(stepPart, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepPart}`);
    }

    let baseValues: number[];
    if (rangePart === "*") {
      baseValues = allValues;
    } else if (rangePart.includes("-")) {
      const [rangeStart, rangeEnd] = rangePart.split("-").map(Number);
      if (isNaN(rangeStart) || isNaN(rangeEnd)) {
        throw new Error(`Invalid range in step expression: ${rangePart}`);
      }
      if (rangeStart < min || rangeEnd > max || rangeStart > rangeEnd) {
        throw new Error(
          `Range ${rangeStart}-${rangeEnd} out of bounds [${min}, ${max}]`
        );
      }
      baseValues = generateRange(rangeStart, rangeEnd);
    } else {
      const start = parseInt(rangePart, 10);
      if (isNaN(start) || start < min || start > max) {
        throw new Error(`Invalid start value in step expression: ${rangePart}`);
      }
      baseValues = generateRange(start, max);
    }

    return baseValues.filter((v) => (v - baseValues[0]) % step === 0);
  }

  // Comma-separated list
  if (field.includes(",")) {
    const parts = field.split(",");
    const values = new Set<number>();

    for (const part of parts) {
      const parsed = parseField(part.trim(), min, max);
      parsed.forEach((v) => values.add(v));
    }

    return Array.from(values).sort((a, b) => a - b);
  }

  // Range (e.g., "1-5")
  if (field.includes("-")) {
    const [rangeStart, rangeEnd] = field.split("-").map(Number);
    if (isNaN(rangeStart) || isNaN(rangeEnd)) {
      throw new Error(`Invalid range: ${field}`);
    }
    if (rangeStart < min || rangeEnd > max || rangeStart > rangeEnd) {
      throw new Error(
        `Range ${rangeStart}-${rangeEnd} out of bounds [${min}, ${max}]`
      );
    }
    return generateRange(rangeStart, rangeEnd);
  }

  // Single number
  const num = parseInt(field, 10);
  if (isNaN(num)) {
    throw new Error(`Invalid cron field value: ${field}`);
  }
  if (num < min || num > max) {
    throw new Error(`Value ${num} out of bounds [${min}, ${max}]`);
  }
  return [num];
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}`
    );
  }

  const [minuteField, hourField, dayOfMonthField, monthField, dayOfWeekField] =
    fields;

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const fieldValues = [
    minuteField,
    hourField,
    dayOfMonthField,
    monthField,
    dayOfWeekField,
  ];

  const result = {} as CronFields;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    result[name] = parseField(fieldValues[i], min, max);
  }

  return result;
}

export default function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: Record<string, unknown> = {}
): Record<string, unknown> {
  if (obj === null || obj === undefined || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = obj;
    return result;
  }

  for (const key of keys) {
    const value = (obj as Record<string, unknown>)[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as Record<string, unknown>, newKey, result);
    } else {
      result[newKey] = value;
    }
  }

  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function range(from: number, to: number): number[] {
  if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step value: */n or start-end/n
  if (segment.includes("/")) {
    const [rangeOrStar, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }
    let base: number[];
    if (rangeOrStar === "*") {
      base = range(min, max);
    } else if (rangeOrStar.includes("-")) {
      const [startStr, endStr] = rangeOrStar.split("-");
      const start = clamp(parseInt(startStr, 10), min, max);
      const end = clamp(parseInt(endStr, 10), min, max);
      base = range(start, end);
    } else {
      const start = clamp(parseInt(rangeOrStar, 10), min, max);
      base = range(start, max);
    }
    return base.filter((_, i) => i % step === 0);
  }

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);
    return range(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron segment: ${segment}`);
  }
  return [clamp(value, min, max)];
}

function parseField(expression: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];
  const segments = expression.split(",");
  const values = new Set<number>();
  for (const segment of segments) {
    for (const v of parseSegment(segment.trim(), min, max)) {
      values.add(v);
    }
  }
  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  const trimmed = expression.trim();
  const parts = trimmed.split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length}`
    );
  }

  const result = {} as CronResult;
  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    result[field] = parseField(parts[i], field);
  }

  return result;
}

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function generateRange(start: number, end: number): number[] {
  if (start > end) throw new Error(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function validateValue(value: number, min: number, max: number, fieldName: string): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}-${max}] for field "${fieldName}"`);
  }
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  // Wildcard
  if (segment === "*") {
    return generateRange(min, max);
  }

  // Step value: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value "${stepPart}" in field "${fieldName}"`);
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (rangePart === "*") {
      rangeStart = min;
      rangeEnd = max;
    } else if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      rangeStart = parseInt(startStr, 10);
      rangeEnd = parseInt(endStr, 10);
      if (isNaN(rangeStart) || isNaN(rangeEnd)) {
        throw new Error(`Invalid range "${rangePart}" in field "${fieldName}"`);
      }
      validateValue(rangeStart, min, max, fieldName);
      validateValue(rangeEnd, min, max, fieldName);
    } else {
      rangeStart = parseInt(rangePart, 10);
      if (isNaN(rangeStart)) {
        throw new Error(`Invalid step expression "${segment}" in field "${fieldName}"`);
      }
      validateValue(rangeStart, min, max, fieldName);
      rangeEnd = max;
    }

    const values: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range "${segment}" in field "${fieldName}"`);
    }
    validateValue(start, min, max, fieldName);
    validateValue(end, min, max, fieldName);
    return generateRange(start, end);
  }

  // Single number
  const num = parseInt(segment, 10);
  if (isNaN(num)) {
    throw new Error(`Invalid value "${segment}" in field "${fieldName}"`);
  }
  validateValue(num, min, max, fieldName);
  return [num];
}

function parseField(field: string, min: number, max: number, fieldName: string): number[] {
  const segments = field.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const values = parseSegment(segment.trim(), min, max, fieldName);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronResult)[];

  return {
    minute: parseField(minuteField, ...FIELD_RANGES.minute, fieldNames[0]),
    hour: parseField(hourField, ...FIELD_RANGES.hour, fieldNames[1]),
    dayOfMonth: parseField(domField, ...FIELD_RANGES.dayOfMonth, fieldNames[2]),
    month: parseField(monthField, ...FIELD_RANGES.month, fieldNames[3]),
    dayOfWeek: parseField(dowField, ...FIELD_RANGES.dayOfWeek, fieldNames[4]),
  };
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function clampDayOfWeek(values: number[]): number[] {
  return [...new Set(values.map((v) => (v === 7 ? 0 : v)))].sort(
    (a, b) => a - b
  );
}

function parseField(
  field: string,
  min: number,
  max: number
): number[] {
  if (field.includes(",")) {
    const parts = field.split(",");
    const values = parts.flatMap((part) => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (field === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  if (field.startsWith("*/")) {
    const step = parseInt(field.slice(2), 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in field: "${field}"`);
    }
    const values: number[] = [];
    for (let i = min; i <= max; i += step) {
      values.push(i);
    }
    return values;
  }

  if (field.includes("/")) {
    const [rangePart, stepPart] = field.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in field: "${field}"`);
    }
    let rangeMin = min;
    let rangeMax = max;
    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [start, end] = rangePart.split("-").map(Number);
        rangeMin = start;
        rangeMax = end;
      } else {
        rangeMin = parseInt(rangePart, 10);
        rangeMax = max;
      }
    }
    if (isNaN(rangeMin) || isNaN(rangeMax) || rangeMin > rangeMax) {
      throw new Error(`Invalid range in field: "${field}"`);
    }
    if (rangeMin < min || rangeMax > max) {
      throw new Error(
        `Range out of bounds in field: "${field}" (expected ${min}-${max})`
      );
    }
    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    return values;
  }

  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range in field: "${field}"`);
    }
    if (start > end) {
      throw new Error(`Range start exceeds end in field: "${field}"`);
    }
    if (start < min || end > max) {
      throw new Error(
        `Range out of bounds in field: "${field}" (expected ${min}-${max})`
      );
    }
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  const num = parseInt(field, 10);
  if (isNaN(num)) {
    throw new Error(`Invalid value in field: "${field}"`);
  }
  if (num < min || num > max) {
    throw new Error(
      `Value ${num} out of bounds in field: "${field}" (expected ${min}-${max})`
    );
  }
  return [num];
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${parts.length}`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const result = {} as CronFields;

  for (let i = 0; i < fieldNames.length; i++) {
    const fieldName = fieldNames[i];
    const { min, max } = FIELD_RANGES[fieldName];
    let values = parseField(parts[i], min, max);

    if (fieldName === "dayOfWeek") {
      values = clampDayOfWeek(values);
    }

    result[fieldName] = values;
  }

  return result;
}
